import { useEffect, useState } from 'react';

import API from '../services/api';

import LeadTable from '../components/LeadTable';

function Leads() {
  const [leads, setLeads] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  const [showModal, setShowModal] =
    useState(false);

  const [editingLead, setEditingLead] =
    useState(null);

  const [counselors, setCounselors] =
    useState([]);

  const [form, setForm] =
    useState({
      fullName: '',
      email: '',
      phoneNumber: '',
      country: '',
      courseInterested: '',
      leadSource: '',
      assignedCounselor: '',
      leadStatus: 'New',
      priority: 'Medium',
      notes: ''
    });

  /*
    FETCH LEADS
  */
  const fetchLeads =
    async () => {
      try {
        setLoading(true);

        const res =
          await API.get(
            '/leads'
          );

        setLeads(
          Array.isArray(
            res.data.leads
          )
            ? res.data.leads
            : []
        );
      } catch (error) {
        console.log(error);

        setLeads([]);
      } finally {
        setLoading(false);
      }
    };

  /*
    FETCH COUNSELORS
  */
  const fetchCounselors =
    async () => {
      try {
        const res =
          await API.get(
            '/auth/counselors'
          );

        setCounselors(
          res.data || []
        );
      } catch (error) {
        console.log(error);
      }
    };

  /*
    INITIAL LOAD
  */
  useEffect(() => {
    fetchLeads();

    fetchCounselors();
  }, []);

  /*
    HANDLE CHANGE
  */
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]:
        e.target.value
    });
  };

  /*
    OPEN ADD MODAL
  */
  const handleAdd = () => {
    setEditingLead(null);

    setForm({
      fullName: '',
      email: '',
      phoneNumber: '',
      country: '',
      courseInterested: '',
      leadSource: '',
      assignedCounselor: '',
      leadStatus: 'New',
      priority: 'Medium',
      notes: ''
    });

    setShowModal(true);
  };

  /*
    EDIT LEAD
  */
  const handleEdit = (lead) => {
    setEditingLead(lead);

    setForm({
      ...lead
    });

    setShowModal(true);
  };

  /*
    SAVE LEAD
  */
  const handleSubmit =
    async (e) => {
      e.preventDefault();

      try {
        if (editingLead) {
          await API.put(
            `/leads/${editingLead._id}`,
            form
          );
        } else {
          await API.post(
            '/leads',
            form
          );
        }

        setShowModal(false);

        fetchLeads();
      } catch (error) {
        console.log(error);
      }
    };

  /*
    DELETE LEAD
  */
  const handleDelete =
    async (id) => {
      try {
        await API.delete(
          `/leads/${id}`
        );

        fetchLeads();
      } catch (error) {
        console.log(error);
      }
    };

  return (
    <div>
      <div className="page-header">
        <h2>
          Lead Management
        </h2>

        <button
          className="btn-primary"
          onClick={handleAdd}
        >
          + Add Lead
        </button>
      </div>

      {loading ? (
        <p>Loading...</p>
      ) : (
        <LeadTable
          leads={leads}
          onEdit={handleEdit}
          onDelete={handleDelete}
        />
      )}

      {showModal && (
        <div className="modal-overlay">
          <div className="modal">
            <h2>
              {editingLead
                ? 'Edit Lead'
                : 'Add New Lead'}
            </h2>

            <form
              onSubmit={
                handleSubmit
              }
            >
              <div className="form-grid">
                <input
                  name="fullName"
                  placeholder="Full Name"
                  value={
                    form.fullName
                  }
                  onChange={
                    handleChange
                  }
                  required
                />

                <input
                  name="email"
                  placeholder="Email"
                  value={
                    form.email
                  }
                  onChange={
                    handleChange
                  }
                  required
                />

                <input
                  name="phoneNumber"
                  placeholder="Phone Number"
                  value={
                    form.phoneNumber
                  }
                  onChange={
                    handleChange
                  }
                />

                <input
                  name="country"
                  placeholder="Country"
                  value={
                    form.country
                  }
                  onChange={
                    handleChange
                  }
                />

                <input
                  name="courseInterested"
                  placeholder="Course Interested"
                  value={
                    form.courseInterested
                  }
                  onChange={
                    handleChange
                  }
                />

                <input
                  name="leadSource"
                  placeholder="Lead Source"
                  value={
                    form.leadSource
                  }
                  onChange={
                    handleChange
                  }
                />

                <select
                  name="assignedCounselor"
                  value={
                    form.assignedCounselor
                  }
                  onChange={
                    handleChange
                  }
                >
                  <option value="">
                    Select Counselor
                  </option>

                  {counselors.map(
                    (c) => (
                      <option
                        key={
                          c._id
                        }
                        value={
                          c.name
                        }
                      >
                        {c.name}
                      </option>
                    )
                  )}
                </select>

                <select
                  name="leadStatus"
                  value={
                    form.leadStatus
                  }
                  onChange={
                    handleChange
                  }
                >
                  <option>
                    New
                  </option>

                  <option>
                    Interested
                  </option>

                  <option>
                    Applied
                  </option>

                  <option>
                    Admitted
                  </option>

                  <option>
                    Rejected
                  </option>
                </select>

                <select
                  name="priority"
                  value={
                    form.priority
                  }
                  onChange={
                    handleChange
                  }
                >
                  <option>
                    Low
                  </option>

                  <option>
                    Medium
                  </option>

                  <option>
                    High
                  </option>
                </select>
              </div>

              <textarea
                name="notes"
                placeholder="Notes"
                value={
                  form.notes
                }
                onChange={
                  handleChange
                }
              />

              <div className="modal-actions">
                <button
                  type="button"
                  onClick={() =>
                    setShowModal(
                      false
                    )
                  }
                >
                  Cancel
                </button>

                <button type="submit">
                  Save Lead
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default Leads;
